const e={hero:{name:"Pablo Olivera",title:"Técnico en Mantenimiento de Sistemas Informáticos",motto:"> odio los problemas, así que los arreglaré uno por uno",copyEmail:" Email",resume:"Hoja de vida"},navbar:{home:"Inicio",skills:"Habilidades",projects:"Proyectos",experience:"Experiencia",education:"Educación",certifications:"Certificados",services:"Servicios"},services:{title:"// Servicios",items:{bugHunter:"Cazador de Errores, Bugs y Fallos de Sistema",mercenary:"Mercenario Especializado en Defensa Digital y Mitigación de Riesgos",exterminator:"Exterminador de Fallos en Redes y Sistemas Críticos",fullstackWorker:"Obrero Fullstack para la construcción de sitios web",entrenador:"Entrenador personal para la seguridad informática"}},skills:{title:"// Perfil y habilidades",whoami:"$ whoami",whoamiText:"Soy el holotipo del llanero araucano, aproximadamente un guitarrista bohemio, un buen amigo, nómada, reservado, curioso, siempre dispuesto a aprender algo nuevo.",objective:"$ cat profile.txt",objectiveText:"Técnico en sistemas informáticos con habilidades en reparación y mantenimiento de hardware y creación de software. Experiencia práctica en desarrollo web y configuración de equipos de red (switches/routers) y soporte técnico presencial. Habilidades blandas desarrolladas como monitor académico.",whatAmI:"¿Qué soy, entonces?",descartesQuote:"«¿Qué soy, entonces? Una cosa que piensa. Y ¿qué es una cosa que piensa? Es una cosa que duda, que entiende, que afirma, que niega, que quiere, que no quiere, que imagina también, y que siente.»",descartesCitation:"Descartes, R. (1641). Meditationes de prima philosophia.",categories:{webDev:"Desarrollo Web",programming:"Programación",networking:"Redes",systems:"Sistemas y Herramientas",security:"Seguridad",hardware:"Hardware"}},projects:{title:"// Proyectos",viewProject:"Ver Proyecto →",uniarauca:{desc:"Creé un sitio web para la representación web oficial de la universidad de Arauca (info e inscripciones)."},dapnfc:{desc:"Implementé un sitio web como catálogo oficial de dapNFC con información del producto y contacto con el vendedor."},mergehelper:{desc:"Construí una extensión de VS Code para detectar y fusionar bloques de código duplicados, asegurando trabajar siempre con la versión más reciente."},scripts:{title:"Scripts de Python",desc:"Elaboré una recopilación de scripts de Python para resolver distintos problemas de automatización y procesamiento de datos."}},experience:{title:"// Experiencia",mired:{position:" Técnico en Mantenimiento y Reparación de Sistemas Informáticos",date:"28/10/2025 - Presente",responsibilities:["Instalación y reparación física de equipos","Formateo de PC, instalación de sistema operativo, creación de copias de seguridad","Configuración de redes LAN y mantenimiento de switches/routers","Soporte técnico a usuarios internos","Mantenimiento de impresoras IP","Arreglar dispositivos con solo mi presencia"]}},education:{title:"// Educación",degree:"Técnico en Mantenimiento de Sistemas Informáticos",institution:"Institución Universitaria de Barranquilla",status:"En prácticas",period:"2024-04 : 2026-04"},certifications:{title:"// Certificaciones",provider:"Cisco Networking Academy",categories:{hardware:"Hardware y Software",networks:"Redes",cybersecurity:"Ciberseguridad",devdata:"Programación y Ciencia de Datos"},certs:{ccna:{name:"CCNA: Fundamentos de Conmutación, Enrutamiento y Redes Inalámbricas",date:"28 ago 2025"},threats:{name:"Gestión de amenazas cibernéticas",date:"28 may 2025"},defense:{name:"Defensa de la red",date:"26 may 2025"},endpoints:{name:"Seguridad de Terminales",date:"23 may 2025"},devices:{name:"Dispositivos de Red y Configuración Inicial",date:"07 abr 2025"},basics:{name:"Conceptos básicos de redes",date:"21 mar 2025"},intro:{name:"Introducción a la Ciberseguridad",date:"16 mar 2025"},awareness:{name:"Conciencia digital",date:"10 mar 2025"},python1:{name:"Fundamentos de Python 1",date:"27 dic 2025"},python2:{name:"Fundamentos de Python 2",date:"26 ene 2026"},hardware_basics:{name:"Conceptos Básicos de Hardware de Computadora",date:"06 ene 2026"},hardware_support:{name:"Hardware and Upgrade Support",date:"20 ene 2026"},it_support:{name:"IT Customer Support Basics",date:"28 ene 2026"},modern_ai:{name:"Introducción a la IA moderna",date:"10 feb 2026"},data_science:{name:"Introducción a la Ciencia de Datos",date:"17 feb 2026"}}},chatbot:{placeholder:"Escribe algo para hablar conmigo...",default:["No estoy seguro de cómo responder a eso, pero como dice mi lema: odio los problemas, así que buscaré una solución.","Buena pregunta, la guardaré para que Pablo la responda más tarde.","System Error: No tengo esa info procesada. Pablo me lo explicará luego.","Interesante... lo añadiré a mi base de datos personalizada algún día."],greeting:"¡Hola! Soy el asistente virtual de Pablo. ¿En qué puedo ayudarte hoy o qué fallo vamos a depurar?",whoami:"Soy Pablo Olivera, técnico en sistemas y 'bug fixer' por naturaleza. Básicamente, si tiene un cable o código y está fallando, yo me encargo.",skills:"Domino redes (Cisco), programación (Python, JS, Java) y mantenimiento de hardware. Si el sistema está mal hecho, ya me empieza a rayar...",contact:"Puedes contactarme por email en jpom1310@gmail.com o encontrarme en LinkedIn y GitHub como Pabl0l. No mandes señales de humo, esas las ignoro.",experience:"Actualmente soy Técnico en Mired IPS. Una vez arreglé el internet de toda una oficina en 5 minutos solo porque unos genios desconectaron el RACK para pintar la pared. Cosas de la vida.",certifications:"Tengo varias certificaciones de Cisco. Sé cómo configurar un router y por qué no deberías dejar que el pintor toque los cables del RACK.",motto:"Mi lema es: 'i hate problems so i will fix them one by one'. Es lo que guía mi trabajo diario y mi desprecio por el código sucio.",tools:"Dame una navaja suiza y arreglaré el mundo.",music:"Soy un melómano total. Rock, metal, jazz, dance hall, electropop... si suena bien, está en mi playlist.",bikes:"Las motos son mi pasión. Nada como la libertad de las dos ruedas para despejar la mente después de un día de bugs.",hates:"Me molestan profundamente los programas y sistemas mal hechos. La eficiencia no es una opción, es una necesidad.",family:"Mi lugar favorito en el mundo es simple: donde estén mi familia y mis amigos.",status:"Con hambre... de comerme al mundo.",movies:"Mis favoritas son 'Don't Look Up' y 'Bugonia'. El fin del mundo es un buen tema si el código no funciona.",food:"Carne de res con papas francesas. Mi combustible favorito para arreglar racks.",hobbies:"Juego LoL, Minecraft y The Binding of Isaac. También me apasiona la naturaleza, los animales y el senderismo. Mi color favorito es el verde, por si no se nota en la terminal.",philosophy:"Soy una navaja suiza: disfruto aprendiendo de todo. Nunca me oirás decir 'no sé' sin añadir un 'pero lo aprendo ya mismo'. El 'no puedo' no existe en mi sistema.",goals:"Mi meta es ser el mejor en lo que hago. Como dice el verso: 'Que si te inspira ser zapatero, sólo quiero que seas el mejor... porque de nada sirve el doctor si es el ejemplo malo del pueblo'.",teamwork:"Prefiero el trabajo en equipo horizontal. Sin jerarquías vacías ni sumisión; solo un grupo de personas dando el 100% por un objetivo común.",location:"Orgullosamente de Arauca, aunque actualmente estoy basado en la 'Puerta de Oro', Barranquilla.",failure:"Para mí, el fracaso no existe, solo es aprendizaje en tiempo de ejecución.",favTech:"Tengo una python en mi bota... 🐍",joke:"Hay 10 tipos de personas en el mundo: las que saben binario y las que no."}},a={hero:{name:"Pablo Olivera",title:"Computer Systems Maintenance Technician",motto:"> I hate problems, so I'll fix them one by one",copyEmail:" Copy Email",resume:"Resume"},navbar:{home:"Home",skills:"Skills",projects:"Projects",experience:"Experience",education:"Education",certifications:"Certifications",services:"Services"},services:{title:"// Services",items:{bugHunter:"System Error Hunter",mercenary:"Mercenary Specialized in Digital Defense and Risk Mitigation",exterminator:"Network Failure Exterminator",fullstackWorker:"Full-Stack Builder for Website Construction",entrenador:"Personal Coach for IT Security"}},skills:{title:"// Profile and Skills",whoami:"$ whoami",whoamiText:"I am the holotype of the Araucanian plainsman: somewhat a bohemian guitarist, a good friend, nomadic, reserved, curious, and always willing to learn something new.",objective:"$ cat profile.txt",objectiveText:"Computer systems technician with skills in hardware repair and maintenance, and software creation. Hands-on experience in web development, network equipment configuration (switches/routers), and on-site technical support. Soft skills developed as an academic tutor.",whatAmI:"What am I, then?",descartesQuote:'"What am I, then? A thing that thinks. And what is a thing that thinks? It is a thing that doubts, understands, affirms, denies, wills, refuses, and also imagines and perceives."',descartesCitation:"Descartes, R. (1641). Meditationes de prima philosophia.",categories:{webDev:"Web Development",programming:"Programming",networking:"Networking",systems:"Systems and Tools",security:"Security",hardware:"Hardware"}},projects:{title:"// Projects",viewProject:"View Project →",uniarauca:{desc:"I created the official website for the University of Arauca (information and registrations)."},dapnfc:{desc:"I implemented a website as the official catalog for dapNFC with product information and seller contact."},mergehelper:{desc:"I built a VS Code extension to detect and merge duplicate code blocks, ensuring work is always done with the latest version."},scripts:{title:"Python Scripts",desc:"I developed a compilation of Python scripts to solve various automation and data processing problems."}},experience:{title:"// Experience",mired:{position:"Computer Systems Maintenance and Repair Intern",date:"28/10/2025 - Present",responsibilities:["Physical installation and repair of equipment","PC formatting, operating system installation, and backup creation","LAN network configuration and switch/router maintenance","Technical support for internal users","IP printer maintenance","Fixing devices with just my presence"]}},education:{title:"// Education",degree:"Computer Systems Maintenance Technician",institution:"University Institution of Barranquilla",status:"Currently in Internship",period:"2024-04 : 2026-04"},certifications:{title:"// Certifications",provider:"Cisco Networking Academy",categories:{hardware:"Hardware and Software",networks:"Networking",cybersecurity:"Cybersecurity",devdata:"Programming and Data Science"},certs:{ccna:{name:"CCNA: Switching, Routing, and Wireless Essentials",date:"28 Aug 2025"},threats:{name:"Cyber Threat Management",date:"28 May 2025"},defense:{name:"Network Defense",date:"26 May 2025"},endpoints:{name:"Endpoint Security",date:"23 May 2025"},devices:{name:"Network Devices and Initial Configuration",date:"07 Apr 2025"},basics:{name:"Networking Basics",date:"21 Mar 2025"},intro:{name:"Introduction to Cybersecurity",date:"16 Mar 2025"},awareness:{name:"Digital Awareness",date:"10 Mar 2025"},python1:{name:"Python Essentials 1",date:"27 Dec 2025"},python2:{name:"Python Essentials 2",date:"26 Jan 2026"},hardware_basics:{name:"Computer Hardware Basics",date:"06 Jan 2026"},hardware_support:{name:"Hardware and Upgrade Support",date:"20 Jan 2026"},it_support:{name:"IT Customer Support Basics",date:"28 Jan 2026"},modern_ai:{name:"Introduction to Modern AI",date:"10 Feb 2026"},data_science:{name:"Introduction to Data Science",date:"17 Feb 2026"}}},chatbot:{placeholder:"Type something to talk to me...",default:["I'm not sure how to respond to that, but as my motto says: I hate problems, so I'll find a solution.","Good question, I'll save it for Pablo to answer later.","System Error: Information not processed. Pablo will explain it to me later.","Interesting... I'll add it to my personal database someday."],greeting:"Hello! I'm Pablo's virtual assistant. How can I help you today, or which bug are we going to debug?",whoami:"I'm Pablo Olivera, a systems technician and 'bug fixer' by nature. Basically, if it has a cable or code and it's broken, I'm your guy.",skills:"I specialize in networking (Cisco), programming (Python, JS, Java), and hardware maintenance. If the system is poorly made, it's starting to bother me...",contact:"You can reach me via email at jpom1310@gmail.com or find me on LinkedIn and GitHub as Pabl0l. Don't send smoke signals; I usually ignore them.",experience:"I'm currently a Maintenance Technician at Mired IPS. I once fixed an entire office's internet in 5 minutes just because some geniuses unplugged the RACK to paint the wall. Life happens.",certifications:"I have several Cisco certifications. I know how to configure a router and why you shouldn't let the painter touch the RACK cables.",motto:"My motto is: 'i hate problems so i will fix them one by one'. It's what drives my daily work and my disdain for dirty code.",tools:"Give me a Swiss Army knife and I'll fix the world. That's what Archimedes meant, but he didn't have a Victorinox handy.",music:"I'm a total music lover. Rock, metal, jazz, dance hall, electropop... if it sounds good, it's on my playlist.",bikes:"Motorcycles are my passion. Nothing like the freedom of two wheels to clear the mind after a day of bugs.",hates:"I am deeply annoyed by poorly made programs and systems. Efficiency is not an option; it's a necessity.",family:"My favorite place in the world is simple: wherever my family and friends are.",status:"Hungry... hungry to take over the world.",movies:"My favorites are 'Don't Look Up' and 'Bugonia'. World's end is a great topic if the code is failing.",food:"Beef with french fries. My favorite fuel for fixing racks.",hobbies:"I play LoL, Minecraft, and The Binding of Isaac. I also love nature, travel, and working out. Green is my color, obviously.",philosophy:"I'm a Swiss Army knife: I love learning about everything. You'll never hear me say 'I don't know' without adding 'but I'll learn it right now'. 'I can't' is not in my command dictionary.",goals:"My goal is to be the best at what I do. As the verse goes: 'If you're inspired to be a shoemaker, I only want you to be the best... because a doctor is useless if he's the bad example of the town'.",teamwork:"I prefer horizontal teamwork. No empty hierarchies or submission; just a group of people giving 100% for a common goal.",location:"Proudly from Arauca, though I'm currently based in the 'Golden Gate', Barranquilla.",failure:"To me, failure doesn't exist; it's just runtime learning.",favTech:"There's a python in my boot... 🐍",joke:"There are 10 types of people in the world: those who understand binary, and those who don't."}},i={hero:{name:"Pablo Olivera",title:"Techniker für Wartung von Computersystemen",motto:"> Ich hasse Probleme – also löse ich sie Stück für Stück",copyEmail:" E-Mail kopieren",resume:"Lebenslauf"},navbar:{home:"Startseite",skills:"Fähigkeiten",projects:"Projekte",experience:"Erfahrung",education:"Ausbildung",certifications:"Zertifizierungen",services:"Dienstleistungen"},services:{title:"// Dienstleistungen",items:{bugHunter:"Jäger von Systemfehlern",mercenary:"Söldner für digitale Verteidigung und Risikominimierung",exterminator:"Vernichter kritischer Netzwerkfehler",fullstackWorker:"Fullstack-Baumeister für Webseitenerstellung",entrenador:"Personal Coach für IT-Sicherheit"}},skills:{title:"// Profil und Fähigkeiten",whoami:"$ whoami",whoamiText:"Ich bin der Holotyp des Llanero aus Arauca: ein etwas bohemischer Gitarrist, guter Freund, Nomade, zurückhaltend, neugierig und stets bereit, etwas Neues zu lernen.",objective:"$ cat profile.txt",objectiveText:"Techniker für Computersysteme mit Fähigkeiten in Hardware-Reparatur, Wartung und Softwareentwicklung. Praxiserfahrung in Webentwicklung, Konfiguration von Netzwerkgeräten (Switches/Routern) und technischem Support vor Ort. Ausgeprägte Soft Skills durch meine Tätigkeit als akademischer Tutor.",whatAmI:"Was bin ich also?",descartesQuote:"„Was bin ich also? Ein Ding, das denkt. Und what ist ein Ding, das denkt? Ein Ding, das zweifelt, versteht, bejaht, verneint, will, nicht will, sich vorstellt und empfindet.“",descartesCitation:"Descartes, R. (1641). Meditationes de prima philosophia.",categories:{webDev:"Webentwicklung",programming:"Programmierung",networking:"Netzwerktechnik",systems:"Systeme und Werkzeuge",security:"Sicherheit",hardware:"Hardware"}},projects:{title:"// Projekte",viewProject:"Projekt ansehen →",uniarauca:{desc:"Ich habe die offizielle Website der Universität von Arauca erstellt (Informationen und Einschreibungen)."},dapnfc:{desc:"Ich habe eine Website als offiziellen Katalog für dapNFC entwickelt – mit Produktinformationen und Verkäuferkontakt."},mergehelper:{desc:"Ich habe eine VS-Code-Erweiterung erstellt, die doppelte Codeblöcke erkennt und zusammenführt, damit stets mit der neuesten Version gearbeitet wird."},scripts:{title:"Python-Skripte",desc:"Ich habe eine Sammlung von Python-Skripten entwickelt, um verschiedene Automatisierungs- und Datenverarbeitungsaufgaben zu lösen."}},experience:{title:"// Berufserfahrung",mired:{position:"Technischer Praktikant für Wartung und Reparatur von Computersystemen",date:"28.10.2025 – heute",responsibilities:["Physische Installation und Reparatur von Geräten","PC-Formatierung, Betriebssysteminstallation und Erstellung von Backups","LAN-Konfiguration und Wartung von Switches/Routern","Technischer Support für interne Nutzer","Wartung von IP-Druckern","Geräte allein durch meine bloße Anwesenheit reparieren"]}},education:{title:"// Ausbildung",degree:"Techniker für Wartung von Computersystemen",institution:"Hochschule Barranquilla",status:"Im Praktikum",period:"04.2024 – 04.2026"},certifications:{title:"// Zertifizierungen",provider:"Cisco Networking Academy",categories:{hardware:"Hardware und Software",networks:"Netzwerke",cybersecurity:"Cybersicherheit",devdata:"Programmierung und Datenwissenschaft"},certs:{ccna:{name:"CCNA: Switching, Routing and Wireless Essentials",date:"28. Aug. 2025"},threats:{name:"Cyber Threat Management",date:"28. Mai 2025"},defense:{name:"Network Defense",date:"26. Mai 2025"},endpoints:{name:"Endpoint Security",date:"23. Mai 2025"},devices:{name:"Network Devices and Initial Configuration",date:"07. Apr. 2025"},basics:{name:"Networking Basics",date:"21. März 2025"},intro:{name:"Introduction to Cybersecurity",date:"16. März 2025"},awareness:{name:"Digital Awareness",date:"10. März 2025"},python1:{name:"Python-Grundlagen 1",date:"27. Dez. 2025"},python2:{name:"Python-Grundlagen 2",date:"26. Jan. 2026"},hardware_basics:{name:"Grundkonzepte der Computer-Hardware",date:"06. Jan. 2026"},hardware_support:{name:"Hardware- und Upgrade-Support",date:"20. Jan. 2026"},it_support:{name:"Grundlagen des IT-Kundensupports",date:"28. Jan. 2026"},modern_ai:{name:"Einführung in moderne KI",date:"10. Feb. 2026"},data_science:{name:"Einführung in die Datenwissenschaft",date:"17. Feb. 2026"}}},chatbot:{placeholder:"Schreib etwas, um mit mir zu sprechen...",default:["Ich bin mir nicht sicher, wie ich darauf antworten soll, aber wie mein Motto sagt: Ich hasse Probleme, also werde ich eine Lösung finden.","Gute Frage, ich werde sie speichern, damit Pablo sie später beantworten kann.","Systemfehler: Informationen nicht verarbeitet. Pablo wird es mir später erklären.","Interessant... ich werde es eines Tages in meine persönliche Datenbank aufnehmen."],greeting:"Hallo! Ich bin Pablos virtueller Assistent. Wie kann ich dir heute helfen, o welchen Fehler werden wir heute beheben?",whoami:"Ich bin Pablo Olivera, Systemtechniker und von Natur aus ein 'Bug-Fixer'. Im Grunde gilt: Wenn es ein Kabel oder Code hat und kaputt ist, bin ich dein Mann.",skills:"Ich beherrsche Netzwerke (Cisco), Programmierung (Python, JS, Java) und Hardware-Wartung. Wenn das System schlecht gemacht ist, fängt es an mich zu nerven...",contact:"Du kannst mich per E-Mail unter jpom1310@gmail.com erreichen oder mich auf LinkedIn und GitHub als Pabl0l finden. Schick keine Rauchzeichen; die ignoriere ich.",experience:"Ich bin derzeit Wartungstechniker bei Mired IPS. Einmal habe ich das Internet eines ganzen Büros in 5 Minuten repariert, nur weil ein paar Genies das RACK ausgesteckt haben, um die Wand zu streichen. So ist das Leben.",certifications:"Ich habe mehrere Cisco-Zertifizierungen. Ich weiß, wie man einen Router konfiguriert und warum man den Maler nicht an die RACK-Kabel lassen sollte.",motto:"Mein Motto lautet: 'i hate problems so i will fix them one by one'. Das ist es, was meine tägliche Arbeit und meine Verachtung für unsauberen Code antreibt.",tools:"Gib mir ein Schweizer Taschenmesser und ich repariere die Welt. Das war es, was Archimedes meinte, aber er hatte kein Victorinox zur Hand.",music:"Ich bin ein totaler Musikliebhaber. Rock, Metal, Jazz, Dancehall, Electropop... wenn es gut klingt, ist es auf meiner Playlist.",bikes:"Motorräder sind meine Leidenschaft. Es geht nichts über die Freiheit auf zwei Rädern, um den Kopf nach einem Tag voller Bugs frei zu bekommen.",hates:"Schlecht gemachte Programme und Systeme nerven mich zutiefst. Effizienz ist keine Option, sondern eine Notwendigkeit.",family:"Mein Lieblingsort auf der Welt ist einfach: dort, wo meine Familie und meine Freunde sind.",status:"Hungrig... hungrig darauf, die Welt zu erobern.",movies:"Meine Favoriten sind 'Don't Look Up' und 'Bugonia'. Das Ende der Welt ist ein tolles Thema, wenn der Code versagt.",food:"Rindfleisch mit Pommes. Mein Lieblingskraftstoff für die Arbeit am Rack.",hobbies:"Ich spiele LoL, Minecraft und The Binding of Isaac. Außerdem liebe ich Natur, Reisen und Sport. Grün ist meine Farbe, ganz klar.",philosophy:"Ich bin ein Schweizer Taschenmesser: Ich liebe es, über alles zu lernen. Du wirst mich nie 'Ich weiß es nicht' sagen hören, ohne ein 'aber ich lerne es sofort' hinzuzufügen. 'Ich kann nicht' steht nicht in meinem Befehlswörterbuch.",goals:"Mein Ziel ist es, der Beste in dem zu sein, was ich tue. Wie es im Vers heißt: 'Wenn es dich inspiriert, Schuster zu sein, möchte ich nur, dass du der Beste bist... denn ein Arzt ist nutzlos, wenn er das schlechte Beispiel der Stadt ist'.",teamwork:"Ich bevorzuge horizontale Teamarbeit. Keine leeren Hierarchien oder Unterwerfung; einfach eine Gruppe von Menschen, die 100% für ein gemeinsames Ziel geben.",location:"Stolz aus Arauca, obwohl ich derzeit im 'Golden Gate', Barranquilla, ansässig bin.",failure:"Für mich gibt es kein Scheitern; es ist nur Lernen zur Laufzeit.",favTech:"Ich habe eine Python in meinem Stiefel... 🐍",joke:"Es gibt 10 Arten von Menschen auf der Welt: die, die Binär verstehen, und die, die es nicht tun."}},n={es:e,en:a,de:i},t="es";export{t as d,n as l};
